// Step 1 & 3: Character with ASC + IAbilitySystemInterface
class AMyCharacter : public ACharacter, public IAbilitySystemInterface
{
    GENERATED_BODY()
public:
    AMyCharacter();
    virtual UAbilitySystemComponent* GetAbilitySystemComponent() const override;

    UPROPERTY(VisibleAnywhere, BlueprintReadOnly)
    UAbilitySystemComponent* AbilitySystemComponent;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly, Category = "GAS")
    TArray<TSubclassOf<UGameplayAbility>> DefaultAbilities;

protected:
    virtual void PossessedBy(AController* NewController) override;
    void GiveDefaultAbilities();
};

// Step 2: AttributeSet
UCLASS()
class UMyAttributeSet : public UAttributeSet
{
    GENERATED_BODY()
public:
    UPROPERTY(ReplicatedUsing=OnRep_Health, BlueprintReadOnly, Category = "Attributes")
    FGameplayAttributeData Health;
    ATTRIBUTE_ACCESSORS(UMyAttributeSet, Health)

    UPROPERTY(ReplicatedUsing=OnRep_MaxHealth, BlueprintReadOnly, Category = "Attributes")
    FGameplayAttributeData MaxHealth;
    ATTRIBUTE_ACCESSORS(UMyAttributeSet, MaxHealth)

protected:
    virtual void PostGameplayEffectExecute(const FGameplayEffectModCallbackData& Data) override;
};

// Step 6: Grant abilities on the server
void AMyCharacter::PossessedBy(AController* NewController)
{
    Super::PossessedBy(NewController);
    AbilitySystemComponent->InitAbilityActorInfo(this, this);
    GiveDefaultAbilities();
}

void AMyCharacter::GiveDefaultAbilities()
{
    if (!HasAuthority()) return;
    for (auto& AbilityClass : DefaultAbilities)
    {
        AbilitySystemComponent->GiveAbility(
            FGameplayAbilitySpec(AbilityClass, 1, INDEX_NONE, this));
    }
}

// AbilityBase.h — base class for all abilities
UCLASS(Blueprintable)
class UAbilityBase : public UObject
{
    GENERATED_BODY()
public:
    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    FName AbilityName;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    float CooldownDuration = 1.f;

    UFUNCTION(BlueprintCallable)
    bool TryActivate(AActor* Owner);

    UFUNCTION(BlueprintNativeEvent)
    bool CanActivate(AActor* Owner);

    UFUNCTION(BlueprintNativeEvent)
    void Execute(AActor* Owner);

    bool IsOnCooldown() const { return GetWorld()->GetTimerManager().IsTimerActive(CooldownTimer); }

protected:
    FTimerHandle CooldownTimer;
};

// AbilityBase.cpp
bool UAbilityBase::TryActivate(AActor* Owner)
{
    if (!CanActivate(Owner)) return false;
    Execute(Owner);
    // Start cooldown
    Owner->GetWorldTimerManager().SetTimer(CooldownTimer, CooldownDuration, false);
    return true;
}

bool UAbilityBase::CanActivate_Implementation(AActor* Owner)
{
    return !IsOnCooldown();
}

// AbilityComponent.h — manages abilities on an Actor
UCLASS(ClassGroup=(Custom), meta=(BlueprintSpawnableComponent))
class UAbilityComponent : public UActorComponent
{
    GENERATED_BODY()
public:
    UPROPERTY(EditDefaultsOnly, Category = "Abilities")
    TArray<TSubclassOf<UAbilityBase>> DefaultAbilityClasses;

    UFUNCTION(BlueprintCallable)
    bool ActivateAbilityByName(FName Name);

protected:
    virtual void BeginPlay() override;
    UPROPERTY()
    TArray<UAbilityBase*> Abilities;
};
